import { describe, it } from "vitest";

// The implementation must expose a function that takes a parsed scenario
// object (matching the input JSON schema) and returns the results object
// (matching the output JSON schema). See example-mapping/claim-office.md
// for the binding interface contract and per-test rationale.

describe("MHPCO Claim Office — quote", () => {
  it.todo(
    "single plain sword, customer 0 years (first insurance) → premium 115 (100 × 1.10 + 5)",
  );

  it.todo(
    "single plain amulet, customer 0 years (first insurance) → premium 71 (60 × 1.10 + 5)",
  );

  it.todo(
    "single plain staff, customer 0 years (first insurance) → premium 93 (80 × 1.10 + 5)",
  );

  it.todo(
    "single plain potion, customer 0 years (first insurance) → premium 49 (40 × 1.10 + 5)",
  );

  it.todo(
    "single cursed sword, customer 0 years → premium 170 (100 × 1.50 × 1.10 + 5)",
  );

  it.todo(
    "single sword with enchantment 5, customer 0 years → premium 148 (100 × 1.30 × 1.10 + 5)",
  );

  it.todo(
    "single sword cursed AND enchantment 5, customer 0 years → premium 220 (ceil(100 × 1.50 × 1.30 × 1.10) + 5)",
  );

  it.todo(
    "single plain sword, customer 2 years (loyal + first insurance) → premium 93 (100 × 0.80 × 1.10 + 5)",
  );

  it.todo(
    "single plain amulet, customer 5 years (loyal + first insurance) → premium 58 (ceil(60 × 0.80 × 1.10) + 5)",
  );

  it.todo(
    "single rune, customer 0 years (first insurance) → premium 33 (ceil(25 × 1.10) + 5)",
  );

  it.todo(
    "three alike runes form one building block, customer 0 years → premium 71 (60 × 1.10 + 5)",
  );

  it.todo(
    "four runes = one building block + one single, customer 0 years → premium 99 (ceil((60 + 25) × 1.10) + 5)",
  );

  it.todo(
    "three runes + three moonstones form two building blocks, customer 0 years → premium 137 ((60 + 60) × 1.10 + 5)",
  );

  it.todo(
    "sword + amulet in one quote, customer 0 years → premium 181 ((100 + 60) × 1.10 + 5)",
  );

  it.todo(
    "two-quote scenario for customer 0 years: first sword quote = 115, second amulet quote = 56 (60 × 0.85 + 5, post-first contract discount)",
  );
});

describe("MHPCO Claim Office — claim", () => {
  it.todo(
    "claim on plain amulet (ench 2, not dragon) damaged by fire for 200 → payout 0 (item does not qualify for reimbursement)",
  );

  it.todo(
    "claim on dragon-material sword for 500 damage → payout 400 (500 at 100% minus 100 deductible)",
  );

  it.todo(
    "claim on sword with enchantment 9 for 500 damage → payout 150 (500 × 0.5 = 250 minus 100 deductible)",
  );

  it.todo(
    "claim on sword with enchantment 9 for 150 damage → payout 0 (150 × 0.5 = 75 minus 100 floored at 0)",
  );

  it.todo(
    "claim on event with dragon sword (300) + enchantment-9 amulet (200) → payout 300 (300 + 200×0.5 = 400 minus 100 deductible)",
  );

  it.todo(
    "claim on event with dragon sword (300) + plain potion (80) → payout 200 (300 + 0 = 300 minus 100; non-qualifying item ignored)",
  );

  it.todo(
    "claim on plain potion for 500 damage → payout 0 (non-qualifying item)",
  );

  it.todo(
    "claim on dragon staff with enchantment 10 for 400 damage → payout 300 (dragon 100% wins over high-ench 50%; 400 minus 100 deductible)",
  );
});

describe("MHPCO Claim Office — CLI", () => {
  it.todo(
    "CLI reads a JSON scenario from stdin and writes a JSON results object to stdout (schema example 2: customer 5 yr, amulet quote then 200 fire claim → {results: [{premium: 58}, {payout: 0}]})",
  );
});
